/* eslint-disable @typescript-eslint/no-magic-numbers */
export enum ColorKeys {
  Green = 'green',
  Blue = 'blue',
  Red = 'red',
  Orange = 'orange',
  Yellow = 'yellow',
  Sunflower = 'sunflower',
  Lime = 'lime',
  Turquoise = 'turquoise',
  Indigo = 'indigo',
  Purple = 'purple',
  Violet = 'violet',
  Carmine = 'carmine',
  Wathet = 'wathet',
  Neutral = 'neutral',
}

export const DEFAULT_COLOR_LEVELS = [50, 100, 200, 300, 400, 500, 600, 700, 800, 900];

export interface Color {
  /**
   * color level
   */
  level: number;
  /**
   * color value
   */
  value: string;
}

export interface PresetColor {
  key: ColorKeys;
  colors: Color[];
}
